protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // HasIndex removed: EF Core 9 Cosmos provider throws instead of silently ignoring.
    // Manage indexing policy via Azure Portal, Bicep, or Terraform.

    modelBuilder.Entity<Product>().ToContainer("Products");

    // Preserve the EF Core 8 discriminator property name so existing documents
    // (which store "Discriminator") remain readable. EF Core 9 defaults to "$type".
    modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

    // Preserve the EF Core 8 compound id format ("Product|123") so existing
    // documents remain accessible via FindAsync / point-reads.
    modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
}

