using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator which is correct
        // because we configured HasDiscriminator("Discriminator") to preserve
        // the EF Core 8 property name (EF Core 9 would default to "$type").
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports sync I/O — use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

